import anthropic, os, requests

client = anthropic.Anthropic()

# Tool defined directly in agent code
TOOLS = [
    {
        "name": "get_weather",
        "description": "Get current weather for a city.",
        "input_schema": {
            "type": "object",
            "properties": {
                "city": {"type": "string", "description": "City name"}
            },
            "required": ["city"],
        },
    }
]

def get_weather(city: str) -> str:
    # Credential lives in the agent's environment
    api_key = os.environ["WEATHER_API_KEY"]
    resp = requests.get(
        "https://api.openweathermap.org/data/2.5/weather",
        params={"q": city, "appid": api_key, "units": "metric"},
        timeout=5,
    )
    resp.raise_for_status()
    data = resp.json()
    return f"{data['name']}: {data['main']['temp']}°C, {data['weather'][0]['description']}"

def dispatch(name: str, args: dict) -> str:
    if name == "get_weather":
        return get_weather(**args)
    raise ValueError(f"Unknown tool: {name}")

# Agent loop
messages = [{"role": "user", "content": "What's the weather in Tokyo?"}]
resp = client.messages.create(model="claude-sonnet-4-6", max_tokens=512,
                               tools=TOOLS, messages=messages)
for block in resp.content:
    if block.type == "tool_use":
        print(dispatch(block.name, block.input))

# Hybrid: some tools are MCP, some are direct
# Use MCP for shared, credential-sensitive tools
# Use direct for agent-specific or lightweight helpers

import anthropic, asyncio
from mcp import ClientSession, StdioServerParameters
from mcp.client.stdio import stdio_client

claude = anthropic.Anthropic()

# Direct tool: no credentials, agent-specific
def format_as_markdown(text: str, title: str = 'Report') -> str:
    return f'# {title}\n\n{text}\n'

DIRECT_TOOLS = [
    {
        "name": "format_as_markdown",
        "description": "Format text as a Markdown document with a title.",
        "input_schema": {
            "type": "object",
            "properties": {
                "text": {"type": "string"},
                "title": {"type": "string"},
            },
            "required": ["text"],
        },
    }
]

async def run(user_message: str):
    params = StdioServerParameters(command='python', args=['github_server.py'])
    async with stdio_client(params) as (read, write):
        async with ClientSession(read, write) as session:
            await session.initialize()
            mcp_result = await session.list_tools()
            mcp_tools = [
                {'name': t.name, 'description': t.description or '',
                 'input_schema': t.inputSchema}
                for t in mcp_result.tools
            ]
            all_tools = mcp_tools + DIRECT_TOOLS
            messages = [{'role': 'user', 'content': user_message}]

            while True:
                resp = claude.messages.create(
                    model='claude-sonnet-4-6', max_tokens=2048,
                    tools=all_tools, messages=messages,
                )
                if resp.stop_reason == 'end_turn':
                    break
                tool_results = []
                for block in resp.content:
                    if block.type != 'tool_use':
                        continue
                    if block.name == 'format_as_markdown':
                        # Dispatch to direct function
                        text = format_as_markdown(**block.input)
                    else:
                        # Dispatch to MCP server
                        result = await session.call_tool(block.name, block.input)
                        text = '\n'.join(c.text for c in result.content if hasattr(c,'text'))
                    tool_results.append({
                        'type': 'tool_result', 'tool_use_id': block.id, 'content': text
                    })
                messages.append({'role': 'assistant', 'content': resp.content})
                messages.append({'role': 'user', 'content': tool_results})
